using Apex.Application.Abstractions.Data;using Apex.Application.Abstractions.Exceptions;using Apex.Application.Abstractions.Time;using Apex.Modules.Accounting.ChartOfAccounts.Domain;using Apex.Modules.Accounting.ChartOfAccounts.Repositories;using Microsoft.AspNetCore.Mvc;
namespace Apex.Modules.Accounting.ChartOfAccounts.UseCases.ArchiveSubsidiaryAccount;
internal sealed class ArchiveSubsidiaryAccountHandler(IGeneralTransactionRunner tx,ISubsidiaryAccountWriteRepository repo,IClock clock){public async Task HandleAsync(long id,CancellationToken ct)=>await tx.ExecuteAsync(async token=>{var v=await repo.GetForUpdateAsync(id,token)??throw new NotFoundException("Subsidiary account was not found.",ChartOfAccountsErrors.SubsidiaryAccountNotFound);v.Archive(clock.UtcNow);await repo.UpdateAsync(v,token);},ct);}
internal static class ArchiveSubsidiaryAccountEndpoint{internal static RouteGroupBuilder MapArchiveSubsidiaryAccountEndpoint(this RouteGroupBuilder g){g.MapPost("/subsidiary-accounts/{id:long}/archive",async(long id,[FromServices]ArchiveSubsidiaryAccountHandler h,CancellationToken ct)=>{await h.HandleAsync(id,ct);return Results.NoContent();}).WithName("ArchiveSubsidiaryAccount");return g;}}
